using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the input message back with a timestamp.")]
    public static string Echo(
        [Description("The message to echo back")] string message)
    {
        return $"[{DateTime.UtcNow:O}] {message}";
    }

    [McpServerTool, Description("Adds two numbers together.")]
    public static double Add(
        [Description("First number")] double a,
        [Description("Second number")] double b)
    {
        return a + b;
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            environment = "production",
            version = "1.0.0",
            features = new { darkMode = true, analytics = false },
            maxRetries = 3,
            timeoutSeconds = 30
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/endpoints",
        Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Returns the list of configured API endpoints.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { name = "users", url = "https://api.example.com/users" },
            new { name = "orders", url = "https://api.example.com/orders" },
            new { name = "products", url = "https://api.example.com/products" }
        };

        return JsonSerializer.Serialize(endpoints, new JsonSerializerOptions { WriteIndented = true });
    }
}

